-- -----------------------------------------------------------------------------
-- notifications — 수신자 후보(앱 pickExistingColumn) + read 후보
--   • authenticated insert/delete 없음(시스템/서비스) — [delete policy 없음=거부]
-- -----------------------------------------------------------------------------
create table if not exists public.notifications (
  id uuid primary key default gen_random_uuid(),
  type text,
  body text,
  is_read boolean not null default false,
  read boolean,
  acknowledged boolean,
  read_at timestamptz,
  read_at_utc timestamptz,
  seen_at timestamptz,
  opened_at timestamptz,
  viewed_at timestamptz,
  acknowledged_at timestamptz,
  metadata jsonb,
  data jsonb,
  -- 수신(정확히 하나는 반드시 설정 권장) — RLS: 아래 id 중 auth.uid() 일치
  user_id uuid references public.users (id) on delete cascade,
  recipient_id uuid references public.users (id) on delete cascade,
  student_id uuid references public.users (id) on delete cascade,
  mentor_id uuid references public.users (id) on delete cascade,
  target_user_id uuid references public.users (id) on delete cascade,
  owner_id uuid references public.users (id) on delete cascade,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint notifications_at_least_one_recipient check (
    user_id is not null
    or recipient_id is not null
    or student_id is not null
    or mentor_id is not null
    or target_user_id is not null
    or owner_id is not null
  )
);
create index if not exists idx_notif_user_unread on public.notifications (user_id, is_read, created_at desc);
create index if not exists idx_notif_recipient on public.notifications (recipient_id, is_read, created_at desc);
drop trigger if exists trg_notif_set_updated on public.notifications;
create trigger trg_notif_set_updated
  before update on public.notifications
  for each row execute function public.set_updated_at();

alter table public.notifications enable row level security;
drop policy if exists "notif_select_own" on public.notifications;
drop policy if exists "notif_select_recipient" on public.notifications;
create policy "notif_select_recipient" on public.notifications
  for select to authenticated
  using (
    (
      (user_id is not null and (select auth.uid()) = user_id) or
      (recipient_id is not null and (select auth.uid()) = recipient_id) or
      (student_id is not null and (select auth.uid()) = student_id) or
      (mentor_id is not null and (select auth.uid()) = mentor_id) or
      (target_user_id is not null and (select auth.uid()) = target_user_id) or
      (owner_id is not null and (select auth.uid()) = owner_id)
    )
  );
drop policy if exists "notif_update_own" on public.notifications;
drop policy if exists "notif_update_recipient_read" on public.notifications;
create policy "notif_update_recipient_read" on public.notifications
  for update to authenticated
  using (
    (
      (user_id is not null and (select auth.uid()) = user_id) or
      (recipient_id is not null and (select auth.uid()) = recipient_id) or
      (student_id is not null and (select auth.uid()) = student_id) or
      (mentor_id is not null and (select auth.uid()) = mentor_id) or
      (target_user_id is not null and (select auth.uid()) = target_user_id) or
      (owner_id is not null and (select auth.uid()) = owner_id)
    )
  )
  with check (
    (
      (user_id is not null and (select auth.uid()) = user_id) or
      (recipient_id is not null and (select auth.uid()) = recipient_id) or
      (student_id is not null and (select auth.uid()) = student_id) or
      (mentor_id is not null and (select auth.uid()) = mentor_id) or
      (target_user_id is not null and (select auth.uid()) = target_user_id) or
      (owner_id is not null and (select auth.uid()) = owner_id)
    )
  );
-- insert: authenticated 막힘(시스템) — notif_delete_own 제거(삭제 policy 없음)
drop policy if exists "notif_delete_own" on public.notifications;

-- =============================================================================
-- [참고] 이 파일은 신규 스키마 + 제약/정책. 기존 002_p0 (좁은 notifications)에서 올릴
--   때: notifications 컬럼/제약/정책 diff 스크립트 별도
-- =============================================================================
-- 미적용. 검토·스테이징 먼저.
-- =============================================================================


-- ===== 003_p0_custom_request_draft.sql =====

-- =============================================================================
-- DRAFT P0 (003) — 맞춤의뢰(포스트·지원·주문) + 주문–결제 연결 + 납품/리비전/메시지/이벤트
--   • 미적용. 001 + 002( payments 등 ) 이후 실행.
--   • compatibility: insertWithCandidates + order lifecycle 리터럴(멀티 status 열) 수용
-- [불확실] admin, 시스템 event insert
-- =============================================================================

create extension if not exists pgcrypto;

create or replace function public.set_updated_at()
returns trigger
language plpgsql
as $fn$
begin
  new.updated_at = now();
  return new;
end;
$fn$;

-- id 혼용 컬럼 → canonical(맞춤의뢰 post_id)
create or replace function public.cra_backfill_post_fk()
returns trigger
language plpgsql
as $cra$
begin
  if new.post_id is null and new.custom_request_post_id is not null then
    new.post_id := new.custom_request_post_id;
  end if;
  if new.post_id is null and new.custom_request_id is not null then
    new.post_id := new.custom_request_id;
  end if;
  if new.post_id is null and new.request_id is not null then
    new.post_id := new.request_id;
  end if;
  return new;
end;
$cra$;

-- 주문: post/student/mentor/application id 동의어 → canonical
create or replace function public.cro_backfill_fks()
returns trigger
language plpgsql
as $fn$
begin
  if new.post_id is null and new.custom_request_post_id is not null then
    new.post_id := new.custom_request_post_id;
  end if;
  if new.post_id is null and new.custom_request_id is not null then
    new.post_id := new.custom_request_id;
  end if;
  if new.post_id is null and new.request_id is not null then
    new.post_id := new.request_id;
  end if;

  if new.application_id is null and new.custom_request_application_id is not null then
    new.application_id := new.custom_request_application_id;
  end if;
  if new.application_id is null and new.selected_application_id is not null then
    new.application_id := new.selected_application_id;
  end if;

  if new.mentor_id is null and new.selected_mentor_id is not null then
    new.mentor_id := new.selected_mentor_id;
  end if;
  if new.mentor_id is null and new.assigned_mentor_id is not null then
    new.mentor_id := new.assigned_mentor_id;
  end if;
  if new.mentor_id is null and new.expert_id is not null then
    new.mentor_id := new.expert_id;
  end if;

  if new.student_id is null and new.buyer_id is not null then
    new.student_id := new.buyer_id;
  end if;
  if new.student_id is null and new.client_id is not null then
    new.student_id := new.client_id;
  end if;
  if new.student_id is null and new.user_id is not null then
    new.student_id := new.user_id;
  end if;
  if new.student_id is null and new.author_id is not null then
    new.student_id := new.author_id;
  end if;
  if new.student_id is null and new.requester_id is not null then
    new.student_id := new.requester_id;
  end if;
  return new;
end;
$fn$;

