-- ===== 005_p0_public_mentor_read_rpc.sql =====

-- =============================================================================
-- P0: 공개 멘토 목록/상세를 위한 읽기 RPC (001 users·mentor_profiles RLS “본인만” 보완)
--  • application layer가 직접 public.users 전체 row(이메일 등)를 공개 SELECT 하지 않도록
--    SECURITY DEFINER + 컬럼 제한(이메일 제외)으로 expose.
--  • **staging·운영** 적용 전 service_role / SQL Editor에서 점검. 운영은 이메일·정책·감사에 맞게 조정.
--  • 장기: 읽기 전용 VIEW + 최소 열, 또는 service_role BFF only.
-- =============================================================================

-- 멘토 목록: 이메일 제외(노출 최소)
drop function if exists public.mentor_directory_list(integer);
create or replace function public.mentor_directory_list(p_limit int default 80)
returns table (
  id uuid,
  role text,
  status text,
  full_name text,
  nickname text,
  grade_level text,
  student_status text,
  birth_date date,
  terms_agreed_at timestamptz,
  privacy_agreed_at timestamptz,
  marketing_agreed boolean,
  created_at timestamptz,
  updated_at timestamptz
)
language sql
stable
security definer
set search_path = public
as $$
  select
    u.id,
    u.role,
    u.status,
    u.full_name,
    u.nickname,
    u.grade_level,
    u.student_status,
    u.birth_date,
    u.terms_agreed_at,
    u.privacy_agreed_at,
    u.marketing_agreed,
    u.created_at,
    u.updated_at
  from public.users u
  where u.role = 'mentor'
  order by u.created_at desc
  limit greatest(1, least(p_limit, 200));
$$;

-- 멘토 1인 공개(상세/구독) — role=mentor 가 아니면 0행
drop function if exists public.mentor_user_public(uuid);
create or replace function public.mentor_user_public(p_mentor_id uuid)
returns table (
  id uuid,
  role text,
  status text,
  full_name text,
  nickname text,
  grade_level text,
  student_status text,
  birth_date date,
  terms_agreed_at timestamptz,
  privacy_agreed_at timestamptz,
  marketing_agreed boolean,
  created_at timestamptz,
  updated_at timestamptz
)
language sql
stable
security definer
set search_path = public
as $$
  select
    u.id,
    u.role,
    u.status,
    u.full_name,
    u.nickname,
    u.grade_level,
    u.student_status,
    u.birth_date,
    u.terms_agreed_at,
    u.privacy_agreed_at,
    u.marketing_agreed,
    u.created_at,
    u.updated_at
  from public.users u
  where u.id = p_mentor_id
    and u.role = 'mentor'
  limit 1;
$$;

-- 멘토 프로필 배치(목록·상세) — RLS “본인만” 보완
drop function if exists public.mentor_profiles_for_directory(uuid[]);
create or replace function public.mentor_profiles_for_directory(p_ids uuid[])
returns setof public.mentor_profiles
language sql
stable
security definer
set search_path = public
as $$
  select mp.*
  from public.mentor_profiles mp
  where p_ids is not null
    and array_length(p_ids, 1) is not null
    and mp.user_id = any (p_ids);
$$;

revoke all on function public.mentor_directory_list(int) from public;
revoke all on function public.mentor_user_public(uuid) from public;
revoke all on function public.mentor_profiles_for_directory(uuid[]) from public;

grant execute on function public.mentor_directory_list(int) to anon, authenticated;
grant execute on function public.mentor_user_public(uuid) to anon, authenticated;
grant execute on function public.mentor_profiles_for_directory(uuid[]) to anon, authenticated;

comment on function public.mentor_directory_list is 'P0 멘토 디렉터리(이메일 제외). 001 RLS로 목록이 비는 문제를 해결.';
comment on function public.mentor_user_public is 'P0 멘토 1인 공개 프로필용 users 행(이메일 제외).';
comment on function public.mentor_profiles_for_directory is 'P0 멘토 user_id[] 에 대한 mentor_profiles.';


-- ===== 006_p0_custom_request_public_post_browse_rpc.sql =====

-- =============================================================================
-- P0: 멘토가 맞춤의뢰 공개 상세(/custom-request/[id])를 읽기 위한 최소 열 RPC
--  • custom_request_posts SELECT RLS(crp_select)는 작성자·동의어 컬럼만 허용 →
--    멘토의 직접 SELECT는 0행 → 앱이 notFound()를 호출하는 문제를 해결.
--  • SECURITY DEFINER로 테이블을 읽되, 반환 컬럼만 제한(작성자 uuid·연락처 등 미포함).
--  • 호출: authenticated 만. 멘토(role) + status=open(또는 state 공개 계열) 일 때만 1행 반환.
--    작성자·관리자는 앱에서 기존 loadCustomPostById(직접 SELECT)로 충분.
--  • staging·운영 적용 전 SQL Editor에서 점검.
-- =============================================================================

drop function if exists public.get_public_custom_request_post_for_browse(uuid);
create or replace function public.get_public_custom_request_post_for_browse(p_post_id uuid)
returns table (
  id uuid,
  title text,
  body text,
  content text,
  subject text,
  description text,
  goal text,
  subcategory text,
  category text,
  due_at timestamptz,
  deadline timestamptz,
  due_date timestamptz,
  deliverable_type text,
  deliverable_format text,
  result_format text,
  output_format text,
  budget_min numeric,
  budget_max numeric,
  state text,
  status text,
  created_at timestamptz,
  updated_at timestamptz
)
language sql
stable
security definer
set search_path = public
as $fn$
  select
    p.id,
    p.title,
    p.body,
    p.content,
    p.subject,
    p.description,
    p.goal,
    p.subcategory,
    p.category,
    p.due_at,
    p.deadline,
    p.due_date,
    p.deliverable_type,
    p.deliverable_format,
    p.result_format,
    p.output_format,
    p.budget_min,
    p.budget_max,
    p.state,
    p.status,
    p.created_at,
    p.updated_at
  from public.custom_request_posts p
  where p.id = p_post_id
    and (select auth.uid()) is not null
    and (
      (select public.is_admin()) = true
      or (
        exists (
          select 1
          from public.users u
          where u.id = (select auth.uid())
            and u.role = 'mentor'
        )
        and (
          lower(trim(coalesce(p.status, ''))) = 'open'
          or lower(trim(coalesce(p.state, ''))) in ('open', 'published')
        )
      )
    )
  limit 1;
$fn$;

revoke all on function public.get_public_custom_request_post_for_browse(uuid) from public;
grant execute on function public.get_public_custom_request_post_for_browse(uuid) to authenticated;

comment on function public.get_public_custom_request_post_for_browse(uuid) is
  'P0 멘토·관리자: 모집 중 맞춤의뢰 상세(최소 열). 작성자 본인은 직접 SELECT(RLS) 사용.';


-- ===== 007_p0_custom_order_revisions_and_order_events_rls.sql =====

-- P0: 학생(의뢰자) 전용 수정 요청 insert, order_events insert(주문 당사자)
-- 선행: 003_p0_custom_request_draft.sql (custom_request_orders, custom_order_revisions, order_events)

-- -----------------------------------------------------------------------------
-- custom_order_revisions: author=본인 + 의뢰자(학생) 당사자만 insert
-- -----------------------------------------------------------------------------
drop policy if exists "crev_ins" on public.custom_order_revisions;
create policy "crev_ins" on public.custom_order_revisions
  for insert to authenticated
  with check (
    author_id = (select auth.uid())
    and exists (
      select 1 from public.custom_request_orders o
      where o.id = custom_request_order_id
        and (
          o.student_id = (select auth.uid())
          or o.buyer_id = (select auth.uid())
          or o.user_id = (select auth.uid())
          or o.client_id = (select auth.uid())
          or o.author_id = (select auth.uid())
          or o.requester_id = (select auth.uid())
        )
    )
  );

-- -----------------------------------------------------------------------------
-- order_events: 당사자 insert(메시지/수정요청 이벤트 기록)
-- -----------------------------------------------------------------------------
drop policy if exists "oev_insert" on public.order_events;
create policy "oev_insert" on public.order_events
  for insert to authenticated
  with check (
    exists (
      select 1 from public.custom_request_orders o
      where
        o.id = custom_request_order_id
        and (
          o.student_id = (select auth.uid())
          or o.mentor_id = (select auth.uid())
          or o.buyer_id = (select auth.uid())
          or o.user_id = (select auth.uid())
          or o.client_id = (select auth.uid())
          or o.author_id = (select auth.uid())
          or o.requester_id = (select auth.uid())
        )
    )
  );


-- ===== 008_p0_disputes_insert_party_rls.sql =====

-- P0: 맞춤의뢰 주문방 — disputes insert 를 학생·멘토(주문 당사자)로 제한.
-- 선행: 004_p0_cash_disputes_admin_draft.sql (disputes, custom_request_orders)
-- 기본 004 `dispute_ins` 는 student_id = auth.uid() 만 허용 → 멘토 신청 불가. 본 정책으로 교체.

drop policy if exists "dispute_ins" on public.disputes;
create policy "dispute_ins" on public.disputes
  for insert to authenticated
  with check (
    (select auth.uid()) in (student_id, mentor_id)
    and custom_request_order_id is not null
    and exists (
      select 1
      from public.custom_request_orders o
      where o.id = custom_request_order_id
        and o.student_id = student_id
        and o.mentor_id = mentor_id
        and (
          o.student_id = (select auth.uid())
          or o.mentor_id = (select auth.uid())
          or o.buyer_id = (select auth.uid())
          or o.user_id = (select auth.uid())
          or o.client_id = (select auth.uid())
          or o.author_id = (select auth.uid())
          or o.requester_id = (select auth.uid())
        )
    )
  );


-- ===== 009_p0_disputes_submitted_by_and_active_unique.sql =====

-- P0: 맞춤의뢰 disputes — submitted_by(감사) + active 분쟁 1건만(부분 유니크 인덱스)
-- 선행: 004( disputes 테이블 ) · 008_p0_disputes_insert_party_rls.sql ( RLS )
-- Staging/운영: Supabase SQL Editor에서 순서대로 적용.

-- ---------------------------------------------------------------------------
-- 1) submitted_by — auth.users 참조(레거시 호환: 열이 이미 있으면 ADD 생략)
-- ---------------------------------------------------------------------------
do $migration$
begin
  if not exists (
    select 1
    from information_schema.columns
    where table_schema = 'public'
      and table_name = 'disputes'
      and column_name = 'submitted_by'
  ) then
    alter table public.disputes
      add column submitted_by uuid null references auth.users (id) on delete set null;
  end if;
end;
$migration$;

comment on column public.disputes.submitted_by is
  '분쟁 접수 시점의 로그인 사용자(auth.users.id). RLS/앱 insert와 별도 감사 추적.';

-- ---------------------------------------------------------------------------
-- 2) 동일 주문에 open / under_review / escalated 인 분쟁 1건만(부분 유니크 인덱스)
--    ( ALTER TABLE ... ADD CONSTRAINT ... WHERE 는 사용하지 않음 )
-- ---------------------------------------------------------------------------
create unique index if not exists disputes_order_active_unique
  on public.disputes (custom_request_order_id)
  where (status in ('open', 'under_review', 'escalated'));

-- NULL custom_request_order_id 행이 여럿이어도(비권장) 인덱스는 서로 충돌하지 않음(PostgreSQL NULL ≠ NULL).

