-- ===== 025_p0_payments_drop_update_own.sql =====

drop policy if exists "payments_update_own" on public.payments;

comment on table public.payments
  is 'Payments are not user-updatable. Payment status transitions must be performed by trusted service-role server code.';


-- ===== 026_p0_msr_insert_subscription_check.sql =====

drop policy if exists "msr_insert_pair" on public.mentor_student_rooms;
drop policy if exists "msr_insert_with_active_subscription" on public.mentor_student_rooms;

create policy "msr_insert_with_active_subscription" on public.mentor_student_rooms
  for insert to authenticated
  with check (
    (select auth.uid()) = student_id
    and exists (
      select 1
      from public.subscriptions s
      where s.student_id = (select auth.uid())
        and s.mentor_id = mentor_student_rooms.mentor_id
        and s.status = 'active'
    )
  );

comment on table public.mentor_student_rooms
  is 'Question rooms require an active subscription for authenticated inserts. Trusted service-role server code may still bypass RLS for controlled room creation.';


-- ===== 027_p0_harden_payments_and_question_room_rls.sql =====

-- =============================================================================
-- 027 P0 harden payments and mentor_student_rooms RLS
--
-- Purpose
-- 1. payments:
--    - Authenticated users must NOT update payment status directly.
--    - Payment status changes must happen only through trusted server/service_role flow.
--
-- 2. mentor_student_rooms:
--    - Authenticated users must NOT insert rooms directly from the client.
--    - Room creation must happen through subscription checkout server flow.
--
-- Notes
-- - This migration intentionally does NOT create an authenticated INSERT policy
--   for mentor_student_rooms.
-- - service_role bypasses RLS, so finalizeSubscriptionCheckout can still create
--   or reuse rooms through the server path.
-- - Run this first on staging if possible.
-- =============================================================================

-- -----------------------------------------------------------------------------
-- A) Harden public.payments
-- -----------------------------------------------------------------------------

-- Remove direct authenticated UPDATE policies.
drop policy if exists "payments_update_own" on public.payments;
drop policy if exists "payments_update_student" on public.payments;
drop policy if exists "payments_user_update" on public.payments;
drop policy if exists "payments_students_update" on public.payments;

-- Remove old broad policy if it exists.
-- This may include UPDATE, so we split read/insert back into narrower policies.
drop policy if exists "payments_self_rw" on public.payments;

-- Keep authenticated read access only for own related rows.
drop policy if exists "payments_select_own" on public.payments;
create policy "payments_select_own" on public.payments
  for select to authenticated
  using (
    (select auth.uid()) in (user_id, student_id, payer_id, mentor_id)
  );

-- Allow users to create only pending/processing payment intents for themselves.
-- Actual success/failure status changes must be done by server/service_role.
drop policy if exists "payments_insert_intent" on public.payments;
create policy "payments_insert_intent" on public.payments
  for insert to authenticated
  with check (
    (select auth.uid()) = user_id
    and status in ('pending', 'processing')
  );

comment on table public.payments is
  'RLS: authenticated users can select own payments and insert pending intents only. No authenticated UPDATE policy.';


-- -----------------------------------------------------------------------------
-- B) Harden public.mentor_student_rooms
-- -----------------------------------------------------------------------------

-- Remove client-side room creation policies.
drop policy if exists "msr_insert_pair" on public.mentor_student_rooms;
drop policy if exists "msr_insert_with_active_subscription" on public.mentor_student_rooms;

-- Remove old broad policy if it exists.
drop policy if exists "msr_pair" on public.mentor_student_rooms;

-- Keep room visibility for participants.
drop policy if exists "msr_select" on public.mentor_student_rooms;
create policy "msr_select" on public.mentor_student_rooms
  for select to authenticated
  using (
    (select auth.uid()) in (student_id, mentor_id)
  );

-- Remove broad participant UPDATE policy.
-- Room rows should generally be controlled by server/service_role because
-- student_id, mentor_id, and subscription_id are security-sensitive.
drop policy if exists "msr_update_parties" on public.mentor_student_rooms;

comment on table public.mentor_student_rooms is
  'RLS: authenticated users can select participant rooms only. No authenticated INSERT or UPDATE policy. Room creation is server/service_role only.';


-- -----------------------------------------------------------------------------
-- C) Verification queries to run manually after applying this SQL
-- -----------------------------------------------------------------------------

-- 1. payments must have no UPDATE policy.
-- Expected result: 0 rows.
-- SELECT policyname, cmd, qual, with_check
-- FROM pg_policies
-- WHERE schemaname = 'public'
--   AND tablename = 'payments'
--   AND cmd = 'UPDATE';

-- 2. mentor_student_rooms must have no INSERT policy.
-- Expected result: 0 rows.
-- SELECT policyname, cmd, with_check
-- FROM pg_policies
-- WHERE schemaname = 'public'
--   AND tablename = 'mentor_student_rooms'
--   AND cmd = 'INSERT';

-- 3. mentor_student_rooms must have no UPDATE policy.
-- Expected result: 0 rows, unless you intentionally add a narrower server-reviewed policy later.
-- SELECT policyname, cmd, qual, with_check
-- FROM pg_policies
-- WHERE schemaname = 'public'
--   AND tablename = 'mentor_student_rooms'
--   AND cmd = 'UPDATE';

-- 4. Detect rooms without subscription_id.
-- Investigate every returned row before launch.
-- SELECT id, student_id, mentor_id, subscription_id, created_at
-- FROM public.mentor_student_rooms
-- WHERE subscription_id IS NULL
-- ORDER BY created_at DESC
-- LIMIT 20;
-- =============================================================================


-- ===== 028_p0_lock_subscriptions_writes.sql =====

-- P0: block authenticated direct INSERT/UPDATE on subscription tables.
-- App writes go through service_role: insertSubscriptionRow in subscribeCheckoutService.ts
-- - Does not change SELECT policies (except: subscriptions_pair is FOR ALL — dropped and
--   replaced with SELECT-only when no SELECT/ALL policy would remain; see 002_p0/002_app drafts).
-- - Does not change payments, mentor_student_rooms.

DO $$
DECLARE
  nsel int;
BEGIN
  -- public.subscriptions
  IF to_regclass('public.subscriptions') IS NOT NULL THEN
    drop policy if exists "subscriptions_insert_student" on public.subscriptions;
    drop policy if exists "subscriptions_update_student" on public.subscriptions;
    drop policy if exists "subscriptions_self_rw" on public.subscriptions;
    drop policy if exists "subscriptions_pair" on public.subscriptions;

    select coalesce(count(*)::int, 0) into nsel
    from pg_policies
    where schemaname = 'public'
      and tablename = 'subscriptions'
      and cmd in ('SELECT', 'ALL');
    if nsel is null then
      nsel := 0;
    end if;
    if nsel = 0 then
      -- Match 002_p0_subscriptions_questions_draft.sql (student_id, mentor_id).
      -- 002_app_core_schema_draft "subscriptions_pair" used coalesce; if your schema
      -- differs, add a SELECT policy manually.
      drop policy if exists "subscriptions_select_parties" on public.subscriptions;
      create policy "subscriptions_select_parties" on public.subscriptions
        for select to authenticated
        using ( (select auth.uid()) in (student_id, mentor_id) );
    end if;
  end if;

  -- public.mentor_subscriptions
  if to_regclass('public.mentor_subscriptions') is not null then
    drop policy if exists "mentor_subscriptions_insert_student" on public.mentor_subscriptions;
    drop policy if exists "mentor_subscriptions_update_student" on public.mentor_subscriptions;
    drop policy if exists "mentor_subscriptions_self_rw" on public.mentor_subscriptions;
  end if;

  -- public.user_subscriptions
  if to_regclass('public.user_subscriptions') is not null then
    drop policy if exists "user_subscriptions_insert_student" on public.user_subscriptions;
    drop policy if exists "user_subscriptions_update_student" on public.user_subscriptions;
    drop policy if exists "user_subscriptions_self_rw" on public.user_subscriptions;
  end if;
END
$$;

-- Check (run in SQL editor; expect no INSERT/UPDATE for these tables from this migration):
-- SELECT schemaname, tablename, policyname, cmd, with_check
-- FROM pg_policies
-- WHERE schemaname = 'public'
--   AND tablename IN ('subscriptions', 'mentor_subscriptions', 'user_subscriptions')
--   AND cmd IN ('INSERT', 'UPDATE')
-- ORDER BY tablename, cmd, policyname;


-- ===== 029_p0_lock_subscription_deletes.sql =====

-- P0: remove authenticated DELETE (and listed FOR ALL / self_rw) policies on subscription tables.
-- Service role is used for subscription lifecycle from the app; students must not delete rows to bypass status.
-- 028: INSERT/UPDATE already locked down; this file targets DELETE and duplicate drops for self_rw/pair.
-- Does not drop or alter SELECT-only policies (e.g. subscriptions_select_parties). Do not create new DELETE policies.

DO $$
BEGIN
  IF to_regclass('public.subscriptions') IS NOT NULL THEN
    drop policy if exists "subscriptions_delete_student" on public.subscriptions;
    drop policy if exists "subscriptions_delete_own" on public.subscriptions;
    drop policy if exists "subscriptions_user_delete" on public.subscriptions;
    drop policy if exists "subscriptions_self_rw" on public.subscriptions;
    drop policy if exists "subscriptions_pair" on public.subscriptions;
  end if;

  IF to_regclass('public.mentor_subscriptions') IS NOT NULL THEN
    drop policy if exists "mentor_subscriptions_delete_student" on public.mentor_subscriptions;
    drop policy if exists "mentor_subscriptions_delete_own" on public.mentor_subscriptions;
    drop policy if exists "mentor_subscriptions_user_delete" on public.mentor_subscriptions;
    drop policy if exists "mentor_subscriptions_self_rw" on public.mentor_subscriptions;
    drop policy if exists "mentor_subscriptions_pair" on public.mentor_subscriptions;
  end if;

  IF to_regclass('public.user_subscriptions') IS NOT NULL THEN
    drop policy if exists "user_subscriptions_delete_student" on public.user_subscriptions;
    drop policy if exists "user_subscriptions_delete_own" on public.user_subscriptions;
    drop policy if exists "user_subscriptions_user_delete" on public.user_subscriptions;
    drop policy if exists "user_subscriptions_self_rw" on public.user_subscriptions;
    drop policy if exists "user_subscriptions_pair" on public.user_subscriptions;
  end if;
END
$$;

-- After apply: no INSERT/UPDATE/DELETE policies on these tables (expected 0 rows):
-- SELECT schemaname, tablename, policyname, cmd, qual, with_check
-- FROM pg_policies
-- WHERE schemaname = 'public'
--   AND tablename IN ('subscriptions', 'mentor_subscriptions', 'user_subscriptions')
--   AND cmd IN ('INSERT', 'UPDATE', 'DELETE')
-- ORDER BY tablename, cmd, policyname;

-- SELECT policies for parties (e.g. subscriptions_select_parties) should still exist; verify:
-- SELECT schemaname, tablename, policyname, cmd, qual
-- FROM pg_policies
-- WHERE schemaname = 'public'
--   AND tablename IN ('subscriptions', 'mentor_subscriptions', 'user_subscriptions')
--   AND cmd = 'SELECT'
-- ORDER BY tablename, policyname;


-- ===== 030_p0_refund_approve_reject_admin_rpc.sql =====

-- P0: 관리자 환불 승인/거절 — 단일 트랜잭션 RPC (service_role 전용)
-- 선행: public.refunds, public.cash_wallets, public.cash_ledger, public.users(role)
--       payments, subscriptions, custom_request_orders, custom_order_settlement_items (해당 플로우 사용 시)
-- idempotent: cash_ledger.idempotency_key = 'refund_credit:' || refund_id
-- 금액: cash_ledger.delta_cents / cash_wallets.balance_cents 는 운영에서 “원” 단위와 동일한 정수를 씁니다.
--       refunds.amount_cents 가 비어 있거나 0 이하면 payments 로 자동 추정하지 않습니다(승인 차단).

-- -----------------------------------------------------------------------------
-- 1) refunds.updated_at 전용 트리거 함수 (set_updated_at 전제 없이 적용 가능)
-- -----------------------------------------------------------------------------
create or replace function public.set_refunds_updated_at()
returns trigger
language plpgsql
security invoker
set search_path = public
as $fn$
begin
  new.updated_at := now();
  return new;
end;
$fn$;

-- -----------------------------------------------------------------------------
-- 2) refunds 컬럼 보강
-- -----------------------------------------------------------------------------
alter table public.refunds add column if not exists updated_at timestamptz not null default now();
alter table public.refunds add column if not exists processed_at timestamptz;
alter table public.refunds add column if not exists processed_by uuid references public.users (id) on delete set null;
alter table public.refunds add column if not exists admin_note text;

drop trigger if exists trg_refunds_set_updated on public.refunds;
create trigger trg_refunds_set_updated
  before update on public.refunds
  for each row execute function public.set_refunds_updated_at();

-- -----------------------------------------------------------------------------
-- 3) approve_refund_request_admin
-- -----------------------------------------------------------------------------
create or replace function public.approve_refund_request_admin(
  p_refund_id uuid,
  p_admin_id uuid,
  p_admin_note text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $function$
declare
  r public.refunds%rowtype;
  v_amount bigint;
  v_settlement_status text;
  v_idem text := 'refund_credit:' || p_refund_id::text;
  v_ledger_id uuid;
  v_existing_delta bigint;
  v_wu int;
  v_admin_ok boolean;
begin
  if p_refund_id is null then
    return jsonb_build_object('ok', false, 'message', '환불 ID가 필요합니다.');
  end if;
  if p_admin_id is null then
    return jsonb_build_object('ok', false, 'message', '관리자 ID가 필요합니다.');
  end if;

  select exists(
    select 1 from public.users u where u.id = p_admin_id and u.role = 'admin'
  ) into v_admin_ok;
  if not coalesce(v_admin_ok, false) then
    raise exception 'ADMIN_REQUIRED';
  end if;

  select * into r from public.refunds where id = p_refund_id for update;
  if not found then
    return jsonb_build_object('ok', false, 'message', '환불 요청을 찾을 수 없습니다.');
  end if;

  if r.status is distinct from 'pending' then
    return jsonb_build_object(
      'ok', true,
      'noop', true,
      'refund_id', p_refund_id,
      'message', '이미 처리되었거나 대기 상태가 아닙니다.',
      'status', r.status
    );
  end if;

  -- 정산 지급 완료 시 자동 환불 차단
  if r.custom_request_order_id is not null then
    select s.status into v_settlement_status
    from public.custom_order_settlement_items s
    where s.custom_request_order_id = r.custom_request_order_id
    limit 1;
    if found and v_settlement_status = 'paid' then
      return jsonb_build_object(
        'ok', false,
        'message', '이미 정산 지급이 완료된 건은 자동 환불할 수 없습니다. 수동 조정이 필요합니다.'
      );
    end if;
  end if;

  if r.amount_cents is null or r.amount_cents <= 0 then
    raise exception '환불 금액이 설정되지 않아 자동 승인할 수 없습니다.';
  end if;

  v_amount := r.amount_cents;

  if v_amount > 1000000000 then
    return jsonb_build_object('ok', false, 'message', '환불 금액이 허용 한도를 초과합니다.');
  end if;

  -- 정산 예정만 취소 (paid 는 위에서 차단)
  if r.custom_request_order_id is not null then
    update public.custom_order_settlement_items s
    set status = 'cancelled', updated_at = now()
    where s.custom_request_order_id = r.custom_request_order_id
      and s.status in ('pending', 'on_hold', 'payable');
  end if;

  insert into public.cash_ledger (
    user_id, delta_cents, reason, ref_type, ref_id, idempotency_key
  )
  values (
    r.user_id, v_amount, 'refund_approved', 'refunds', r.id, v_idem
  )
  on conflict (idempotency_key) do nothing
  returning id into v_ledger_id;

  if v_ledger_id is null then
    select cl.delta_cents into v_existing_delta
    from public.cash_ledger cl
    where cl.idempotency_key = v_idem
    limit 1;
    if not found then
      raise exception 'REFUND_LEDGER_IDEMPOTENT_MISS' using errcode = 'P0001';
    end if;
    if v_existing_delta is distinct from v_amount then
      raise exception 'REFUND_LEDGER_AMOUNT_MISMATCH' using errcode = 'P0001';
    end if;
  end if;

  if v_ledger_id is not null then
    insert into public.cash_wallets (user_id, balance_cents)
    values (r.user_id, 0)
    on conflict (user_id) do nothing;

    update public.cash_wallets w
    set balance_cents = w.balance_cents + v_amount
    where w.user_id = r.user_id;
    get diagnostics v_wu = row_count;
    if coalesce(v_wu, 0) = 0 then
      raise exception 'CASH_WALLET_UPDATE_FAILED' using errcode = 'P0001';
    end if;
  end if;

  update public.refunds
  set
    status = 'succeeded',
    processed_at = now(),
    processed_by = p_admin_id,
    admin_note = p_admin_note,
    updated_at = now()
  where id = r.id;

  if r.payment_id is not null then
    update public.payments p
    set status = 'refunded', updated_at = now()
    where p.id = r.payment_id;
  end if;

  if r.payment_id is not null then
    update public.subscriptions s
    set status = 'canceled', updated_at = now()
    where s.payment_id = r.payment_id
      and s.status is distinct from 'canceled';
  end if;

  if r.custom_request_order_id is not null then
    update public.custom_request_orders o
    set payment_status = 'refunded', updated_at = now()
    where o.id = r.custom_request_order_id;
  end if;

  return jsonb_build_object(
    'ok', true,
    'noop', false,
    'refund_id', r.id,
    'ledger_inserted', (v_ledger_id is not null),
    'amount_cents', v_amount,
    'message', '환불이 승인되었습니다.'
  );
end;
$function$;

-- -----------------------------------------------------------------------------
-- 4) reject_refund_request_admin
-- -----------------------------------------------------------------------------
create or replace function public.reject_refund_request_admin(
  p_refund_id uuid,
  p_admin_id uuid,
  p_admin_note text default null
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $function$
declare
  r public.refunds%rowtype;
  v_admin_ok boolean;
begin
  if p_refund_id is null then
    return jsonb_build_object('ok', false, 'message', '환불 ID가 필요합니다.');
  end if;
  if p_admin_id is null then
    return jsonb_build_object('ok', false, 'message', '관리자 ID가 필요합니다.');
  end if;

  select exists(
    select 1 from public.users u where u.id = p_admin_id and u.role = 'admin'
  ) into v_admin_ok;
  if not coalesce(v_admin_ok, false) then
    raise exception 'ADMIN_REQUIRED';
  end if;

  select * into r from public.refunds where id = p_refund_id for update;
  if not found then
    return jsonb_build_object('ok', false, 'message', '환불 요청을 찾을 수 없습니다.');
  end if;

  if r.status is distinct from 'pending' then
    return jsonb_build_object(
      'ok', true,
      'noop', true,
      'refund_id', p_refund_id,
      'message', '이미 처리되었거나 대기 상태가 아닙니다.',
      'status', r.status
    );
  end if;

  update public.refunds
  set
    status = 'rejected',
    processed_at = now(),
    processed_by = p_admin_id,
    admin_note = p_admin_note,
    updated_at = now()
  where id = r.id;

  return jsonb_build_object(
    'ok', true,
    'noop', false,
    'refund_id', r.id,
    'message', '환불이 거절되었습니다.'
  );
end;
$function$;

-- -----------------------------------------------------------------------------
-- 5) EXECUTE: service_role 만 (승인/거절 RPC)
-- -----------------------------------------------------------------------------
revoke all on function public.approve_refund_request_admin(uuid, uuid, text) from public;
revoke all on function public.approve_refund_request_admin(uuid, uuid, text) from anon;
revoke all on function public.approve_refund_request_admin(uuid, uuid, text) from authenticated;
grant execute on function public.approve_refund_request_admin(uuid, uuid, text) to service_role;

revoke all on function public.reject_refund_request_admin(uuid, uuid, text) from public;
revoke all on function public.reject_refund_request_admin(uuid, uuid, text) from anon;
revoke all on function public.reject_refund_request_admin(uuid, uuid, text) from authenticated;
grant execute on function public.reject_refund_request_admin(uuid, uuid, text) to service_role;

comment on function public.approve_refund_request_admin(uuid, uuid, text)
  is 'P0: Admin refund approve — idempotent ledger credit, service_role only. Caller must enforce app-level admin; RPC re-checks users.role=admin.';

comment on function public.reject_refund_request_admin(uuid, uuid, text)
  is 'P0: Admin refund reject — refunds row only, service_role only.';

comment on function public.set_refunds_updated_at()
  is 'P0: refunds.updated_at only — independent of public.set_updated_at.';


-- ===== 031_p1_admin_notices_promotions.sql =====

-- P1: 관리자 공지(app_notices) · 프로모션(promotion_campaigns)
-- 선행: 001 public.users (id references auth.users)
-- Idempotent: 여러 번 실행해도 안전
-- RLS: admin만 쓰기; 활성·기간 내 행은 anon/authenticated 조회 가능

create extension if not exists "pgcrypto";

-- ---------------------------------------------------------------------------
-- updated_at 전용 트리거 함수 (이 파일에서 정의, set_updated_at에 비의존)
-- ---------------------------------------------------------------------------
create or replace function public.set_admin_content_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

-- ---------------------------------------------------------------------------
-- public.app_notices
-- ---------------------------------------------------------------------------
create table if not exists public.app_notices (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  body text not null default '',
  type text not null default 'notice',
  target text null,
  is_active boolean not null default false,
  starts_at timestamptz null,
  ends_at timestamptz null,
  created_by uuid null references public.users (id) on delete set null,
  updated_by uuid null references public.users (id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint app_notices_title_nonempty check (char_length(trim(title)) > 0),
  constraint app_notices_type_allowed check (type in ('notice', 'event', 'maintenance', 'update')),
  constraint app_notices_date_range check (
    starts_at is null or ends_at is null or ends_at >= starts_at
  )
);

create index if not exists app_notices_created_at_idx on public.app_notices (created_at desc);
create index if not exists app_notices_active_window_idx on public.app_notices (is_active, starts_at, ends_at);

drop trigger if exists trg_app_notices_set_updated on public.app_notices;
create trigger trg_app_notices_set_updated
  before update on public.app_notices
  for each row execute function public.set_admin_content_updated_at();

-- ---------------------------------------------------------------------------
-- public.promotion_campaigns
-- ---------------------------------------------------------------------------
create table if not exists public.promotion_campaigns (
  id uuid primary key default gen_random_uuid(),
  title text not null,
  body text not null default '',
  target text null,
  is_active boolean not null default false,
  starts_at timestamptz null,
  ends_at timestamptz null,
  created_by uuid null references public.users (id) on delete set null,
  updated_by uuid null references public.users (id) on delete set null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint promotion_campaigns_title_nonempty check (char_length(trim(title)) > 0),
  constraint promotion_campaigns_date_range check (
    starts_at is null or ends_at is null or ends_at >= starts_at
  )
);

create index if not exists promotion_campaigns_created_at_idx on public.promotion_campaigns (created_at desc);
create index if not exists promotion_campaigns_active_window_idx on public.promotion_campaigns (is_active, starts_at, ends_at);

drop trigger if exists trg_promotion_campaigns_set_updated on public.promotion_campaigns;
create trigger trg_promotion_campaigns_set_updated
  before update on public.promotion_campaigns
  for each row execute function public.set_admin_content_updated_at();

-- ---------------------------------------------------------------------------
-- RLS
-- ---------------------------------------------------------------------------
alter table public.app_notices enable row level security;
alter table public.promotion_campaigns enable row level security;

-- app_notices: admin 전체 조회 · 활성+기간 내 공개 조회
drop policy if exists "app_notices_select" on public.app_notices;
create policy "app_notices_select"
  on public.app_notices for select
  to anon, authenticated
  using (
    exists (
      select 1 from public.users u
      where u.id = auth.uid() and u.role = 'admin'
    )
    or (
      coalesce(is_active, false) = true
      and (starts_at is null or starts_at <= now())
      and (ends_at is null or ends_at >= now())
    )
  );

drop policy if exists "app_notices_insert_admin" on public.app_notices;
create policy "app_notices_insert_admin"
  on public.app_notices for insert
  to authenticated
  with check (
    exists (select 1 from public.users u where u.id = auth.uid() and u.role = 'admin')
  );

drop policy if exists "app_notices_update_admin" on public.app_notices;
create policy "app_notices_update_admin"
  on public.app_notices for update
  to authenticated
  using (exists (select 1 from public.users u where u.id = auth.uid() and u.role = 'admin'))
  with check (exists (select 1 from public.users u where u.id = auth.uid() and u.role = 'admin'));

drop policy if exists "app_notices_delete_admin" on public.app_notices;
create policy "app_notices_delete_admin"
  on public.app_notices for delete
  to authenticated
  using (exists (select 1 from public.users u where u.id = auth.uid() and u.role = 'admin'));

-- promotion_campaigns
drop policy if exists "promotion_campaigns_select" on public.promotion_campaigns;
create policy "promotion_campaigns_select"
  on public.promotion_campaigns for select
  to anon, authenticated
  using (
    exists (
      select 1 from public.users u
      where u.id = auth.uid() and u.role = 'admin'
    )
    or (
      coalesce(is_active, false) = true
      and (starts_at is null or starts_at <= now())
      and (ends_at is null or ends_at >= now())
    )
  );

drop policy if exists "promotion_campaigns_insert_admin" on public.promotion_campaigns;
create policy "promotion_campaigns_insert_admin"
  on public.promotion_campaigns for insert
  to authenticated
  with check (
    exists (select 1 from public.users u where u.id = auth.uid() and u.role = 'admin')
  );

drop policy if exists "promotion_campaigns_update_admin" on public.promotion_campaigns;
create policy "promotion_campaigns_update_admin"
  on public.promotion_campaigns for update
  to authenticated
  using (exists (select 1 from public.users u where u.id = auth.uid() and u.role = 'admin'))
  with check (exists (select 1 from public.users u where u.id = auth.uid() and u.role = 'admin'));

drop policy if exists "promotion_campaigns_delete_admin" on public.promotion_campaigns;
create policy "promotion_campaigns_delete_admin"
  on public.promotion_campaigns for delete
  to authenticated
  using (exists (select 1 from public.users u where u.id = auth.uid() and u.role = 'admin'));

-- ---------------------------------------------------------------------------
-- Grants (RLS와 함께 사용)
-- ---------------------------------------------------------------------------
grant select on public.app_notices to anon, authenticated;
grant select on public.promotion_campaigns to anon, authenticated;
grant insert, update, delete on public.app_notices to authenticated;
grant insert, update, delete on public.promotion_campaigns to authenticated;
